# === Basic configuration ===
import logging

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s | %(name)s | %(levelname)s | %(message)s',
    datefmt='%Y-%m-%dT%H:%M:%S%z',  # ISO 8601
)

logger = logging.getLogger(__name__)
logger.info('service started')
logger.error('request failed', exc_info=True)  # includes traceback

# === dictConfig (production standard) ===
import logging.config

LOGGING_CONFIG = {
    'version': 1,
    'disable_existing_loggers': False,
    'formatters': {
        'json': {
            '()': 'pythonjsonlogger.jsonlogger.JsonFormatter',
            'format': '%(asctime)s %(name)s %(levelname)s %(message)s',
        },
    },
    'handlers': {
        'stdout': {
            'class': 'logging.StreamHandler',
            'stream': 'ext://sys.stdout',
            'formatter': 'json',
        },
    },
    'root': {
        'level': 'INFO',
        'handlers': ['stdout'],
    },
}

logging.config.dictConfig(LOGGING_CONFIG)

# === Always use getLogger(__name__) at module level ===
# In myapp/service/api.py:
# logger = logging.getLogger(__name__)
# Produces: myapp.service.api as the logger name

# === contextvars for per-request context ===
import contextvars
import uuid

_request_id: contextvars.ContextVar[str] = contextvars.ContextVar('request_id')
_user_id: contextvars.ContextVar[int | None] = contextvars.ContextVar('user_id', default=None)

def get_request_id() -> str:
    return _request_id.get()

def set_request_context(request_id: str | None = None, user_id: int | None = None):
    _request_id.set(request_id or str(uuid.uuid4()))
    if user_id is not None:
        _user_id.set(user_id)

# === Middleware for Flask/FastAPI (injects context into logs) ===
class RequestContextMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        request_id = request.headers.get('X-Request-ID', str(uuid.uuid4()))
        set_request_context(request_id=request_id, user_id=getattr(request, 'user_id', None))
        response = self.get_response(request)
        response.headers['X-Request-ID'] = request_id  # return to client
        return response

# === Logging filter to inject correlation ID into every log record ===
class CorrelationFilter(logging.Filter):
    def filter(self, record):
        record.request_id = get_request_id()
        return True

logging.getLogger().addFilter(CorrelationFilter())

# Now every log line automatically includes request_id:
logger.info('processing order')  # includes request_id from ContextVar

# === PII redaction filter ===
import re

class PIIRedactionFilter(logging.Filter):
    SENSITIVE_PATTERNS = [
        (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b'), '[EMAIL]'),
        (re.compile(r'\b(\d{3}[.-]?){2}\d{4}\b'), '[PHONE]'),
        (re.compile(r'\b(?:\d[ -]*?){13,16}\b'), '[CC]'),
        (re.compile(r'(Bearer|Authorization):\s*\S+'), r'\1: [REDACTED]'),
        (re.compile(r'(password|secret|token|api_key)=[^&\s]+', re.I), r'\1=[REDACTED]'),
    ]

    def filter(self, record):
        if hasattr(record, 'msg') and isinstance(record.msg, str):
            for pattern, replacement in self.SENSITIVE_PATTERNS:
                record.msg = pattern.sub(replacement, record.msg)
            if record.args:
                record.args = tuple(
                    pattern.sub(replacement, str(a)) if isinstance(a, str) else a
                    for a in record.args
                )
        return True

logging.getLogger().addFilter(PIIRedactionFilter())

# === Structured logging: exclude sensitive fields ===
def safe_log_user_data(user: dict) -> dict:
    ALLOWED_FIELDS = {'user_id', 'created_at', 'plan', 'is_active'}
    return {k: v for k, v in user.items() if k in ALLOWED_FIELDS}

# === Never log raw request data ===
# BAD: logger.info(f'request data: {request.body}')
# GOOD: logger.info('request processed', extra={'user_id': user.id, 'action': action})
